function updateSegmentSelects() {
    const schSel = document.getElementById('segSchoolSelect'); const subSel = document.getElementById('segSubjectSelect'); const oldSch = schSel.value;
    schSel.innerHTML = '<option value="ALL">鍏ㄤ埂闀?/option>'; Object.keys(SCHOOLS).forEach(s => schSel.innerHTML += `<option value="${s}">${s}</option>`); if (oldSch && (oldSch === 'ALL' || SCHOOLS[oldSch])) schSel.value = oldSch;
    const oldSub = subSel.value; subSel.innerHTML = '<option value="total">鎬诲垎</option>'; SUBJECTS.forEach(s => subSel.innerHTML += `<option value="${s}">${s}</option>`); if (oldSub) subSel.value = oldSub;
}

function renderSegmentAnalysis() {
    const school = document.getElementById('segSchoolSelect').value;
    const subject = document.getElementById('segSubjectSelect').value;
    const step = parseInt(document.getElementById('segStep').value) || 10;

    let students = school === 'ALL' ? RAW_DATA : (SCHOOLS[school] ? SCHOOLS[school].students : []);
    const validStudents = students.filter(s => {
        const v = subject === 'total' ? s.total : s.scores[subject];
        return typeof v === 'number';
    }).map(s => ({
        ...s, // 娴呮嫹璐濆鐢熶俊鎭?        _filterScore: subject === 'total' ? s.total : s.scores[subject]
    }));

    const scores = validStudents.map(s => s._filterScore); // 鍏煎鏃ч€昏緫鐨?scores 鏁扮粍鐢ㄤ簬璁＄畻 max/total

    if (!scores.length) { alert('娌℃湁鎵惧埌鐩稿叧鎴愮哗鏁版嵁'); return; }

    const maxScore = Math.ceil(Math.max(...scores));
    const topCeil = Math.ceil(maxScore / step) * step;

    let html = `<thead><tr><th>鍒嗘暟娈?/th><th>浜烘暟</th><th>绱浜烘暟</th><th>姣斾緥</th><th>绱姣斾緥</th></tr></thead><tbody>`;
    let cumulative = 0, total = scores.length;

    // 馃煝 鍑嗗鍥捐〃鏁版嵁瀹瑰櫒
    const rowsData = []; // 涓存椂瀛樺偍鏁版嵁浠ヤ究鍚庣画缁欏浘琛ㄤ娇鐢?
    // 浠庨珮鍒颁綆閬嶅巻鐢熸垚琛ㄦ牸
    for (let high = topCeil; high > 0; high -= step) {
        const low = high - step;
        const isTopBucket = high === topCeil;
        const bucketList = validStudents.filter(s => {
            const val = s._filterScore;
            return val >= low && (isTopBucket ? val <= high : val < high);
        });
        const count = bucketList.length;

        // 浼樺寲锛氬幓鎺変袱澶村潎涓?鐨勭┖琛岋紝浣嗕繚鐣欎腑闂寸殑0浠ヤ綋鐜版柇灞?        if (count === 0 && cumulative === 0) continue;

        cumulative += count;

        const label = `${low}-${high}`;

        html += `<tr><td>${label} 鍒?/td><td>${count}</td><td>${cumulative}</td><td>${(count / total * 100).toFixed(2)}%</td><td>${(cumulative / total * 100).toFixed(2)}%</td></tr>`;

        // 鏀堕泦鍥捐〃鏁版嵁 (浣跨敤 unshift 瀛樺叆澶撮儴锛屼繚璇佸浘琛ㄦ槸浠庝綆鍒嗗埌楂樺垎鎺掑垪锛岀鍚堢洿鏂瑰浘涔犳儻)
        rowsData.unshift({
            label: label,
            count: count,
            studentList: bucketList // 馃憟 鍏抽敭锛氫繚瀛樿鍒嗘暟娈电殑瀛︾敓鍚嶅崟
        });
    }

    document.getElementById('tb-segment').innerHTML = html + `</tbody>`;

    // 馃煝 缁樺埗鍥捐〃鏍稿績閫昏緫
    const ctx = document.getElementById('segmentChart');
    if (ctx) {
        // 濡傛灉宸叉湁鍥捐〃瀹炰緥锛屽厛閿€姣侊紝闃叉閲嶅奖
        if (segmentChartInstance) segmentChartInstance.destroy();

        segmentChartInstance = new Chart(ctx, {
            type: 'bar',
            data: {
                labels: rowsData.map(d => d.label),
                datasets: [{
                    label: '浜烘暟鍒嗗竷',
                    data: rowsData.map(d => d.count),
                    backgroundColor: 'rgba(59, 130, 246, 0.6)', // 钃濊壊鏌变綋
                    borderColor: 'rgba(59, 130, 246, 1)',
                    borderWidth: 1,
                    borderRadius: 4,
                    barPercentage: 0.9, // 璁╂煴瀛愬涓€鐐癸紝鏇存湁鐩存柟鍥剧殑鎰熻
                    categoryPercentage: 0.9,
                    order: 2
                }, {
                    // 澧炲姞涓€鏉″钩婊戞洸绾?(瓒嬪娍绾?
                    type: 'line',
                    label: '鍒嗗竷瓒嬪娍',
                    data: rowsData.map(d => d.count),
                    borderColor: '#f59e0b', // 姗欒壊绾挎潯
                    borderWidth: 2,
                    tension: 0.4, // 骞虫粦鏇茬嚎
                    pointRadius: 0,
                    order: 1
                }]
            },
            options: {
                responsive: true,
                maintainAspectRatio: false,
                onClick: (event, elements) => {
                    if (!elements || elements.length === 0) return;

                    // 鑾峰彇琚偣鍑荤殑鏁版嵁鐐圭储寮?                    const index = elements[0].index;
                    const dataItem = rowsData[index];

                    if (dataItem && dataItem.count > 0) {
                        // 璋冪敤 DrillSystem (閽诲彇绯荤粺) 鏄剧ず璇ュ垎鏁版鐨勫鐢熷悕鍗?                        // 鏍囬濡傦細鍏ㄩ晣 璇枃 鍒嗘暟娈佃鎯?(110-120)
                        const title = `${school === 'ALL' ? '鍏ㄩ晣' : school} ${subject} 鍒嗘暟娈佃鎯?(${dataItem.label})`;
                        DrillSystem.open(title, dataItem.studentList);
                    } else {
                        UI.toast('璇ュ垎鏁版鏆傛棤瀛︾敓', 'info');
                    }
                },
                onHover: (event, chartElement) => {
                    // 榧犳爣鎮仠鏃跺彉鎴愬皬鎵嬪浘鏍囷紝鎻愮ず鍙偣鍑?                    event.native.target.style.cursor = chartElement[0] ? 'pointer' : 'default';
                },
                plugins: {
                    legend: { display: true },
                    title: {
                        display: true,
                        text: `${school === 'ALL' ? '鍏ㄩ晣' : school} ${subject} 鎴愮哗鍒嗗竷鐩存柟鍥?(馃挕鐐瑰嚮鏌卞瓙鍙煡鐪嬪悕鍗?`,
                        font: { size: 16 }
                    },
                    tooltip: {
                        mode: 'index',
                        intersect: false,
                    }
                },
                scales: {
                    y: {
                        beginAtZero: true,
                        title: { display: true, text: '浜烘暟' }
                    },
                    x: {
                        title: { display: true, text: '鍒嗘暟娈?(浣?鈫?楂?' }
                    }
                }
            }
        });
    }
}

